//! `third-eye run --static-cam` — a fixed camera (a desk webcam does not pan) perceives a moving
//! object correctly.
//!
//! WHY: the live-webcam perception route writes the FULL `scene_to_tick` payload (metacog +
//! affordances + accumulatedKnowledge) only via the `run` subcommand. A fixed camera with a moving
//! object can have the object mistaken for a camera pan and warped out by global-motion
//! compensation. `--static-cam` is the existing camera-motion-compensation toggle: it sets
//! `VisionConfig.compensate = false`, the same field `run_scene`/`run_track`/`run_detect` set.
//!
//! This test asserts two things, honestly scoped to "the flag toggles the existing mechanism":
//!   (1) MECHANISM — at the vision layer (the field both subcommands share), a moving blob on a
//!       textured-but-static background is detected WITH compensation off (static-cam) and is
//!       suppressed as global motion WITH compensation on (the default). No new perception invented.
//!   (2) PLUMBING — the real `run` binary, fed the same clip over `--rgb-stream` stdin, writes the
//!       full `--out` payload; passing `--static-cam` changes the produced run (the flag reaches the
//!       per-frame vision config) and the object is carried through to the published tick stream.

use std::io::Write;
use std::process::{Command, Stdio};

use third_eye::frame::Frame;
use third_eye::vision::{BackgroundModel, VisionConfig, detect};

const W: u32 = 160;
const H: u32 = 120;
const FPS: f64 = 24.0;
const N: usize = 16; // past the default background warm-up

/// A FIXED-CAMERA stimulus: a textured-but-static background (a deterministic checker/noise field
/// that does NOT move frame-to-frame) with one bright blob that DOES move. This is exactly the
/// "desk webcam, moving object" case: the camera is still, only the object translates.
fn synth_static_bg_moving_blob(frame: usize) -> Vec<u8> {
    let (w, h) = (W as i32, H as i32);
    let mut rgb = vec![0u8; (W * H * 3) as usize];
    // Static textured background: a fixed pseudo-random-ish field, identical on every frame (the
    // camera does not pan, so the texture is anchored to pixel coords, not to the object).
    for y in 0..h {
        for x in 0..w {
            let i = ((y * w + x) * 3) as usize;
            let t = (((x * 7 + y * 13) ^ (x * 3)) & 0x3f) as u8; // fixed per pixel, 0..63
            rgb[i] = 40 + t;
            rgb[i + 1] = 40 + t;
            rgb[i + 2] = 40 + t;
        }
    }
    // Moving blob: translates left->right across frames.
    let half = 14i32;
    let bx = 24 + (frame as i32) * 7;
    let by = h / 2;
    for y in (by - half).max(0)..(by + half).min(h) {
        for x in (bx - half).max(0)..(bx + half).min(w) {
            let i = ((y * w + x) * 3) as usize;
            rgb[i] = 235;
            rgb[i + 1] = 245;
            rgb[i + 2] = 95;
        }
    }
    rgb
}

fn clip_frames() -> Vec<Frame> {
    (0..N)
        .map(|i| Frame {
            index: i as u64,
            pts_s: i as f64 / FPS,
            width: W,
            height: H,
            rgb: synth_static_bg_moving_blob(i),
        })
        .collect()
}

/// Count frames on which `detect` proposed at least one object, under a given compensation setting.
fn frames_with_detection(frames: &[Frame], compensate: bool) -> usize {
    let mut bg = BackgroundModel::new();
    let mut cfg = VisionConfig::default();
    cfg.compensate = compensate;
    let mut hits = 0;
    for f in frames {
        let (props, _fg) = detect(f, &mut bg, &cfg);
        if !props.is_empty() {
            hits += 1;
        }
    }
    hits
}

/// MECHANISM: the field `--static-cam` toggles is `VisionConfig.compensate`. With it OFF (the
/// static-cam config) the moving object on a fixed background is tracked; with it ON (the default)
/// the single moving region is treated as global camera motion and compensated away. This is the
/// documented finding, asserted at the exact config field shared by `run` and `run_scene`.
#[test]
fn static_cam_config_field_tracks_moving_object_on_fixed_background() {
    let frames = clip_frames();

    // run_scene / run_track / run_detect set `vcfg.compensate = false` on --static-cam; run now does
    // the same. Default VisionConfig has compensate = true.
    assert!(
        VisionConfig::default().compensate,
        "default config compensates global motion (the no-flag behavior)"
    );

    let with_static_cam = frames_with_detection(&frames, false); // compensate = false (--static-cam)
    let without = frames_with_detection(&frames, true); // compensate = true (default)

    assert!(
        with_static_cam > 0,
        "with --static-cam (compensate off) the moving object is perceived on a fixed camera"
    );
    assert!(
        with_static_cam > without,
        "static-cam (compensate off, {with_static_cam} hits) tracks the object more than the \
         compensating default ({without} hits), which warps the lone moving region out as pan"
    );
}

/// Pack the clip to a single RGB24 stdin stream (the in-memory transport the perceive route uses).
fn packed_stream(frames: &[Frame]) -> Vec<u8> {
    let mut s = Vec::with_capacity(frames.len() * (W * H * 3) as usize);
    for f in frames {
        s.extend_from_slice(&f.rgb);
    }
    s
}

/// Run the REAL release binary: `third-eye run - --rgb-stream WxH@fps [--static-cam] --out <out>`,
/// piping the packed clip over stdin. Returns the bytes written to `out` (the full scene_to_tick
/// payload: metacog + affordances + accumulatedKnowledge per frame).
fn run_binary(stream: &[u8], static_cam: bool, out_path: &std::path::Path) -> Vec<u8> {
    let bin = env!("CARGO_BIN_EXE_third-eye");
    let mut cmd = Command::new(bin);
    cmd.arg("run")
        .arg("-")
        .arg("--rgb-stream")
        .arg(format!("{W}x{H}@{FPS}"))
        .arg("--out")
        .arg(out_path)
        .arg("--target-fps")
        .arg("1000"); // keep stride at 1 so every frame is processed (deterministic payload)
    if static_cam {
        cmd.arg("--static-cam");
    }
    let mut child = cmd
        .stdin(Stdio::piped())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .spawn()
        .expect("spawn third-eye run");
    child
        .stdin
        .take()
        .expect("stdin")
        .write_all(stream)
        .expect("pipe frames");
    let status = child.wait().expect("wait third-eye run");
    assert!(status.success(), "third-eye run exited non-zero (static_cam={static_cam})");
    std::fs::read(out_path).expect("read --out payload")
}

/// Count published ticks (frames) in an aeon payload, and how many carry a non-empty `entities`
/// array. Each tick's payload is the `scene_to_tick` JSON (the FULL scene_to_tick payload: it
/// carries `entities`, `interactions`, `affordances`, `counterfactuals`, `accumulatedKnowledge`,
/// and `metacog` — this is the only subcommand that writes that whole object to --out).
fn payload_tick_stats(buf: &[u8]) -> (usize, usize, bool) {
    use third_eye::publish::decode_tick;
    let mut off = 0usize;
    let mut ticks = 0usize;
    let mut with_entities = 0usize;
    let mut full_payload = true;
    while let Some((tick, read)) = decode_tick(buf, off) {
        off += read;
        ticks += 1;
        let json = String::from_utf8_lossy(&tick.payload);
        // A non-empty entities array means the moving object reached the published tick.
        if json.contains("\"entities\":[") && !json.contains("\"entities\":[]") {
            with_entities += 1;
        }
        // Confirm the FULL scene_to_tick payload (the reason the route uses `run`): metacog +
        // affordances + accumulatedKnowledge are all present in every published frame.
        if !(json.contains("\"metacog\":")
            && json.contains("\"affordances\":")
            && json.contains("\"accumulatedKnowledge\":"))
        {
            full_payload = false;
        }
    }
    (ticks, with_entities, full_payload)
}

/// PLUMBING: the real `run` binary accepts `--static-cam`, writes the full `--out` payload, and the
/// flag reaches the per-frame vision config — the produced run differs from the no-flag run, and the
/// fixed-camera moving object is carried through to published entities.
#[test]
fn run_binary_static_cam_writes_full_payload_and_tracks_object() {
    let frames = clip_frames();
    let stream = packed_stream(&frames);

    let dir = std::env::temp_dir();
    let pid = std::process::id();
    let out_static = dir.join(format!("third_eye_static_cam_on_{pid}.aeon"));
    let out_default = dir.join(format!("third_eye_static_cam_off_{pid}.aeon"));

    let payload_static = run_binary(&stream, true, &out_static);
    let payload_default = run_binary(&stream, false, &out_default);

    // The full payload is written (non-empty) and round-trips as a tick stream in BOTH runs.
    assert!(!payload_static.is_empty(), "--static-cam run wrote a payload");
    assert!(!payload_default.is_empty(), "default run wrote a payload");
    let (ticks_static, ent_static, full_static) = payload_tick_stats(&payload_static);
    let (ticks_default, ent_default, _full_default) = payload_tick_stats(&payload_default);
    assert!(ticks_static > 0, "static-cam payload decodes to >=1 tick");
    assert!(ticks_default > 0, "default payload decodes to >=1 tick");
    assert!(
        full_static,
        "the --static-cam run writes the FULL scene_to_tick payload (metacog + affordances + \
         accumulatedKnowledge) — the reason the perceive route uses `run`"
    );

    // The flag reaches the per-frame vision config: with the fixed-camera moving-object clip, the
    // static-cam run carries the object through to published entities on at least as many frames as
    // the compensating default, and the two runs are not byte-identical (the flag changed the run).
    assert!(
        ent_static > 0,
        "with --static-cam the fixed-camera moving object reaches published entities"
    );
    assert!(
        ent_static >= ent_default,
        "static-cam ({ent_static} frames w/ entities) tracks the object at least as well as the \
         compensating default ({ent_default}) on a fixed camera"
    );
    assert_ne!(
        payload_static, payload_default,
        "--static-cam changes the produced run (the flag reaches the vision config, not a no-op)"
    );

    let _ = std::fs::remove_file(&out_static);
    let _ = std::fs::remove_file(&out_default);
}
